mapper.select:
SELECT o.id, IFNULL(e.name, '--') AS elderName, IFNULL(e.bed_number, '--') AS bedNumber, o.project_name AS projectName, o.item_type AS itemType, GROUP_CONCAT(DISTINCT n.name SEPARATOR ', ') AS nurseName, o.applicant_name AS applicantName, o.expected_service_time AS expectedServiceTime, o.create_time AS createTime, o.order_no AS orderNo, MAX(oe.execute_status) AS executeStatus FROM lc_service_order o LEFT JOIN elder e ON o.elder_id = e.id LEFT JOIN lc_elder_nurse_assign en ON e.id = en.elder_id LEFT JOIN lc_nurse n ON en.nurse_id = n.id LEFT JOIN lc_nursing_task_execution oe ON o.id = oe.order_id
WHERE 1=1
AND e.name LIKE CONCAT('%', #{query.elderName}, '%')
AND n.name = #{query.nurseName}
AND o.item_type = #{query.itemType}
AND oe.execute_status = #{query.executeStatus}
AND o.expected_service_time >= #{query.beginTime}
AND o.expected_service_time <= #{query.endTime}
GROUP BY o.id ORDER BY o.create_time DESC

mapper.update:
UPDATE lc_service_order
SET expected_service_time = #{expectedServiceTime}
WHERE id = (SELECT order_id FROM lc_nursing_task_execution WHERE order_id = #{id})

